1	'use strict';
2	// 세 도구의 설정 홈 경로와 동기화 대상 위치를 정의한다.
3	// 모드(mode.js)에 따라 읽는 곳이 갈린다:
4	//  - dummy : 프로젝트 안 fixtures/ (실제 파일 안 건드림)
5	//  - real  : 실제 ~/.claude 등 (사용자가 토글을 켤 때만)
6	// canonical/backups도 모드별로 분리해 더미 데이터와 실제 데이터가 섞이지 않게 한다.
7	
8	const os = require('os');
9	const path = require('path');
10	const mode = require('./mode');
11	
12	const PROJECT = path.join(__dirname, '..');
13	
14	function home() {
15	  return os.homedir();
16	}
17	
18	// 더미 모드에서 읽을 fixtures 루트
19	function fixturesRoot() {
20	  return process.env.AAD_FIXTURES || path.join(PROJECT, 'fixtures');
21	}
22	
23	// 각 도구의 설정 홈 디렉토리 (모드에 따라 fixtures vs 실제 홈)
24	function toolHomes() {
25	  if (mode.getMode() === 'dummy') {
26	    const f = fixturesRoot();
27	    return {
28	      claude: path.join(f, 'claude'),
29	      codex: path.join(f, 'codex'),
30	      gemini: path.join(f, 'gemini'),
31	    };
32	  }
33	  return {
34	    claude: path.join(home(), '.claude'),
35	    codex: path.join(home(), '.codex'),
36	    gemini: path.join(home(), '.gemini'),
37	  };
38	}
39	
40	// 지시문 트랙: 도구별 글로벌 지시문 파일명 (canonical 1벌 → 파일명만 바꿔 배포)
41	const INSTRUCTION_FILENAME = {
42	  claude: 'CLAUDE.md',
43	  codex: 'AGENTS.md',
44	  gemini: 'GEMINI.md',
45	};
46	
47	const TOOLS = ['claude', 'codex', 'gemini'];
48	
49	// 도구의 글로벌 지시문 파일 절대 경로
50	function instructionPath(tool) {
51	  return path.join(toolHomes()[tool], INSTRUCTION_FILENAME[tool]);
52	}
53	
54	// agent 트랙: 도구별 agent 폴더와 파일 확장자/경로
55	//  - Claude/Gemini: .md (frontmatter + 본문) / Codex: .toml (developer_instructions)  ← 0번 검증
56	function agentDir(tool) {
57	  return path.join(toolHomes()[tool], 'agents');
58	}
59	function agentExt(tool) {
60	  return tool === 'codex' ? '.toml' : '.md';
61	}
62	function agentPath(tool, name) {
63	  return path.join(agentDir(tool), name + agentExt(tool));
64	}
65	
66	// skill 트랙 (D11):
67	//  - .agents/skills = 여러 도구가 공유하는 cross-tool 표준 위치(에이전트 소속 아님)
68	//  - ~/.codex/skills = 공식 문서엔 없는 비공식 위치(실재) → official:false로 표시
69	function agentsHome() {
70	  return mode.getMode() === 'dummy' ? path.join(fixturesRoot(), 'agents') : path.join(home(), '.agents');
71	}
72	
73	// 스캔할 skill 소스 목록. official=false면 사용자에게 "비공식"으로 알린다.
74	function skillSources() {
75	  const h = toolHomes();
76	  return [
77	    { id: 'claude-user', tool: 'claude', dir: path.join(h.claude, 'skills'), official: true },
78	    { id: 'claude-plugins', tool: 'claude', dir: path.join(h.claude, 'plugins'), official: true, plugin: true, recursive: true },
79	    { id: 'shared-agents', tool: 'shared', dir: path.join(agentsHome(), 'skills'), official: true, shared: true },
80	    { id: 'codex-native', tool: 'codex', dir: path.join(h.codex, 'skills'), official: false },
81	    { id: 'gemini-user', tool: 'gemini', dir: path.join(h.gemini, 'skills'), official: true },
82	  ];
83	}
84	
85	// push(쓰기) 대상 디렉토리 — 공식 위치 기준
86	function skillTargetDir(tool) {
87	  const h = toolHomes();
88	  if (tool === 'claude') return path.join(h.claude, 'skills');
89	  if (tool === 'codex') return path.join(agentsHome(), 'skills'); // 공식 USER 위치
90	  if (tool === 'gemini') return path.join(h.gemini, 'skills');
91	  throw new Error('알 수 없는 도구: ' + tool);
92	}
93	
94	// canonical 저장소 위치 (프로젝트 안 — D5). 모드별로 분리(더미/실제 데이터 안 섞이게).
95	function canonicalRoot() {
96	  if (process.env.AAD_CANONICAL) return process.env.AAD_CANONICAL;
97	  return mode.getMode() === 'dummy'
98	    ? path.join(PROJECT, '.dummy', 'canonical')
99	    : path.join(PROJECT, 'canonical');
100	}
101	
102	// 배포본 덮어쓰기 전 백업을 모아둘 폴더 (모드별 분리)
103	function backupRoot() {
104	  if (process.env.AAD_BACKUPS) return process.env.AAD_BACKUPS;
105	  return mode.getMode() === 'dummy'
106	    ? path.join(PROJECT, '.dummy', 'backups')
107	    : path.join(PROJECT, 'backups');
108	}
109	
110	// 번들 정적 카탈로그(스토어). 모드 무관 — 실제 사용자 데이터가 아니라 프로젝트에 포함된
111	// 큐레이션 목록이다(외부 통신 없음). 환경변수로 오버라이드 가능.
112	function catalogPath() {
113	  return process.env.AAD_CATALOG || path.join(PROJECT, 'catalog', 'catalog.json');
114	}
115	
116	// ─── 프로젝트 스코프 (T1) ───
117	// 저장소(프로젝트) 레벨 skill/agent/지시문 위치.
118	// 근거: docs/verification/project-scope-verification.md (0번 검증 — 공식 문서 확인 완료).
119	
120	// 등록된 프로젝트 목록(projects.json) 저장 위치.
121	// canonicalRoot()가 이미 모드별(.dummy/canonical vs canonical)로 분리돼 있어
122	// 더미/실제 레지스트리가 자동으로 격리된다.
123	function projectsFile() {
124	  return path.join(canonicalRoot(), 'projects.json');
125	}
126	
127	// 프로젝트 레벨 skill 소스 목록 — skillSources() 항목과 같은 형태에
128	// scope:'project' 와 projectRoot 를 더한다.
129	//  - claude: <root>/.claude/skills  (공식)
130	//  - shared: <root>/.agents/skills  (cross-tool 표준 — Codex 공식 위치이자 Gemini 별칭.
131	//    ※ .codex/skills 는 공식 문서에 없어 만들지 않는다 — 0번 검증)
132	//  - gemini: <root>/.gemini/skills  (공식)
133	function projectSkillSources(root) {
134	  return [
135	    { id: 'claude-project', tool: 'claude', dir: path.join(root, '.claude', 'skills'), official: true, scope: 'project', projectRoot: root },
136	    { id: 'shared-project', tool: 'shared', dir: path.join(root, '.agents', 'skills'), official: true, shared: true, scope: 'project', projectRoot: root },
137	    { id: 'gemini-project', tool: 'gemini', dir: path.join(root, '.gemini', 'skills'), official: true, scope: 'project', projectRoot: root },
138	  ];
139	}
140	
141	// 프로젝트 레벨 agent 폴더 — 파일 확장자는 글로벌과 동일하게 agentExt(tool) 사용.
142	//  - claude: <root>/.claude/agents/*.md / codex: <root>/.codex/agents/*.toml / gemini: <root>/.gemini/agents/*.md
143	function projectAgentDir(root, tool) {
144	  if (tool === 'claude') return path.join(root, '.claude', 'agents');
145	  if (tool === 'codex') return path.join(root, '.codex', 'agents');
146	  if (tool === 'gemini') return path.join(root, '.gemini', 'agents');
147	  throw new Error('알 수 없는 도구: ' + tool);
148	}
149	
150	// 프로젝트 지시문 파일 후보 경로 (도구별 배열 — 존재 확인은 호출자 몫).
151	//  - Claude는 두 위치 모두 공식("either ./CLAUDE.md or ./.claude/CLAUDE.md").
152	function projectInstructionPaths(root) {
153	  return {
154	    claude: [path.join(root, 'CLAUDE.md'), path.join(root, '.claude', 'CLAUDE.md')],
155	    codex: [path.join(root, 'AGENTS.md')],
156	    gemini: [path.join(root, 'GEMINI.md')],
157	  };
158	}
159	
160	// "최초 1회" 프로젝트 스캔의 기본 루트.
161	//  - dummy: fixtures/projects (가짜 프로젝트만 — 실제 디스크 안 훑음)
162	//  - real : 사용자 홈 디렉토리
163	function projectScanDefaultRoot() {
164	  return mode.getMode() === 'dummy' ? path.join(fixturesRoot(), 'projects') : home();
165	}
166	
167	// ─── 원격 레지스트리 (스토어-R1) ───
168	// 등록된 레지스트리 목록(registries.json) 저장 위치.
169	// canonicalRoot()가 모드별(.dummy/canonical vs canonical)로 분리돼 있어
170	// 더미/실제 레지스트리가 자동으로 격리된다(projectsFile과 동일 패턴).
171	function registriesFile() {
172	  return path.join(canonicalRoot(), 'registries.json');
173	}
174	
175	// 레지스트리 clone/파싱 캐시 디렉토리. 번들 원본(catalog.json)은 건드리지 않고
176	// 여기(catalog/cache)에만 registry-<id>.json 및 임시 clone을 둔다.
177	function registryCacheDir() {
178	  return process.env.AAD_REGISTRY_CACHE || path.join(PROJECT, 'catalog', 'cache');
179	}
180	
181	module.exports = {
182	  TOOLS,
183	  catalogPath,
184	  INSTRUCTION_FILENAME,
185	  toolHomes,
186	  instructionPath,
187	  agentDir,
188	  agentExt,
189	  agentPath,
190	  agentsHome,
191	  skillSources,
192	  skillTargetDir,
193	  canonicalRoot,
194	  backupRoot,
195	  // 프로젝트 스코프 (T1)
196	  projectsFile,
197	  projectSkillSources,
198	  projectAgentDir,
199	  projectInstructionPaths,
200	  projectScanDefaultRoot,
201	  // 원격 레지스트리 (스토어-R1)
202	  registriesFile,
203	  registryCacheDir,
204	};
205

1	'use strict';
2	// 트랙 B — agent 변환. 중립 스키마 ↔ 세 도구 포맷.
3	//  - Claude/Gemini: .md + YAML frontmatter, 본문 = system_prompt   (gray-matter)
4	//  - Codex:        .toml, developer_instructions = system_prompt   (@iarna/toml)
5	//  - tools: Claude↔Gemini만 이름 매핑(확인된 것만). 미확인/Codex는 "손실(⚠)"로 표시.
6	//
7	// 중립 스키마(JSON):
8	//   { id, name, description, system_prompt, model, tools:[Claude이름...], source_tool, source_notes }
9	
10	const matter = require('gray-matter');
11	const TOML = require('@iarna/toml');
12	const toolMap = require('./tool-map');
13	
14	// ---------- 중립 스키마 → 각 도구 포맷 (render) ----------
15	function render(neutral, tool) {
16	  const losses = [];
17	  if (tool === 'claude') {
18	    const fm = clean({ name: neutral.name, description: neutral.description, model: neutral.model, tools: neutral.tools });
19	    return { tool, ext: '.md', content: matter.stringify('\n' + (neutral.system_prompt || ''), fm), losses };
20	  }
21	  if (tool === 'gemini') {
22	    const mapped = [];
23	    for (const t of neutral.tools || []) {
24	      const g = toolMap.claudeToGemini(t);
25	      if (g) mapped.push(g);
26	      else losses.push(`tools: '${t}' → Gemini 매핑 미확인(제외)`);
27	    }
28	    const fm = clean({ name: neutral.name, description: neutral.description, model: neutral.model, tools: mapped });
29	    return { tool, ext: '.md', content: matter.stringify('\n' + (neutral.system_prompt || ''), fm), losses };
30	  }
31	  if (tool === 'codex') {
32	    // Codex는 에이전트별 tools 필드가 없음 → tools 전부 손실
33	    for (const t of neutral.tools || []) losses.push(`tools: '${t}' → Codex 미지원(에이전트별 tools 없음)`);
34	    const obj = clean({
35	      name: neutral.name,
36	      description: neutral.description,
37	      model: neutral.model,
38	      developer_instructions: neutral.system_prompt || '',
39	    });
40	    return { tool, ext: '.toml', content: TOML.stringify(obj), losses };
41	  }
42	  throw new Error('알 수 없는 도구: ' + tool);
43	}
44	
45	// ---------- 각 도구 포맷 → 중립 스키마 (parse, pull용) ----------
46	function parse(content, tool, name) {
47	  if (tool === 'claude') {
48	    const { data, content: body } = matter(content);
49	    return base(name, data, body.trim(), data.tools || [], 'claude');
50	  }
51	  if (tool === 'gemini') {
52	    const { data, content: body } = matter(content);
53	    const claudeTools = [];
54	    const notes = [];
55	    for (const g of data.tools || []) {
56	      const c = toolMap.geminiToClaude(g);
57	      if (c) claudeTools.push(c);
58	      else notes.push(`Gemini 도구 '${g}' → Claude 매핑 미확인`);
59	    }
60	    const n = base(name, data, body.trim(), claudeTools, 'gemini');
61	    if (notes.length) n.source_notes = notes.join('; ');
62	    return n;
63	  }
64	  if (tool === 'codex') {
65	    const data = TOML.parse(content);
66	    // Codex는 tools가 없음 → 중립 tools는 빈 배열
67	    const n = base(name, data, (data.developer_instructions || '').trim(), [], 'codex');
68	    return n;
69	  }
70	  throw new Error('알 수 없는 도구: ' + tool);
71	}
72	
73	// ---------- 보조 ----------
74	function base(name, data, systemPrompt, tools, sourceTool) {
75	  return {
76	    id: 'agent-' + (data.name || name),
77	    name: data.name || name,
78	    description: data.description || '',
79	    system_prompt: systemPrompt,
80	    model: data.model || null,
81	    tools,
82	    source_tool: sourceTool,
83	  };
84	}
85	
86	// undefined/null/빈배열 필드는 빼서 출력이 깔끔하도록
87	function clean(obj) {
88	  const out = {};
89	  for (const [k, v] of Object.entries(obj)) {
90	    if (v === undefined || v === null) continue;
91	    if (Array.isArray(v) && v.length === 0) continue;
92	    out[k] = v;
93	  }
94	  return out;
95	}
96	
97	module.exports = { render, parse };
98

1	'use strict';
2	// 도구 이름 매핑 (0번 검증 결과). 중립 vocab = Claude 이름(PascalCase) 기준.
3	// ⚠ 원칙: "확인된" 매핑만 둔다. 미확인 도구는 추측하지 말고 매핑하지 않는다(→ 손실 처리).
4	
5	// Claude 이름 ↔ Gemini 이름 (공식 문서에서 확인된 것만)
6	const CLAUDE_TO_GEMINI = {
7	  Read: 'read_file',
8	  Bash: 'run_shell_command',
9	  Grep: 'grep_search',
10	};
11	
12	const GEMINI_TO_CLAUDE = Object.fromEntries(
13	  Object.entries(CLAUDE_TO_GEMINI).map(([c, g]) => [g, c])
14	);
15	
16	// Claude 도구 → Gemini 도구. 모르면 null (호출자가 손실로 표시).
17	function claudeToGemini(name) {
18	  if (name === '*' || name.startsWith('mcp_')) return name; // 와일드카드는 그대로
19	  return CLAUDE_TO_GEMINI[name] || null;
20	}
21	
22	// Gemini 도구 → Claude(중립) 도구. 모르면 null.
23	function geminiToClaude(name) {
24	  if (name === '*' || name.startsWith('mcp_')) return name;
25	  return GEMINI_TO_CLAUDE[name] || null;
26	}
27	
28	module.exports = { CLAUDE_TO_GEMINI, claudeToGemini, geminiToClaude };
