1	#!/usr/bin/env node
2	'use strict';
3	// aad = ai-agent-dashboard CLI. 로직은 cli/core.js에 있고, 여기서는 출력만 한다.
4	// 안전 흐름: push는 기본 미리보기(dry-run), 실제 쓰기는 --apply가 있어야 한다.
5	
6	const core = require('../cli/core');
7	const diff = require('../cli/diff');
8	
9	// --- 아주 작은 인자 파서 (--key value, --flag) ---
10	function parseArgs(argv) {
11	  const out = { _: [] };
12	  for (let i = 0; i < argv.length; i++) {
13	    const a = argv[i];
14	    if (a.startsWith('--')) {
15	      const key = a.slice(2);
16	      const next = argv[i + 1];
17	      if (next && !next.startsWith('--')) {
18	        out[key] = next;
19	        i++;
20	      } else {
21	        out[key] = true;
22	      }
23	    } else {
24	      out._.push(a);
25	    }
26	  }
27	  return out;
28	}
29	
30	function cmdStatus() {
31	  const ov = core.overview();
32	  console.log('지시문 트랙 상태 (canonical id: ' + ov.canonId + ')');
33	  console.log('canonical: ' + (ov.canonicalExists ? `있음 (출처: ${ov.source})` : '없음 — 먼저 pull 하세요'));
34	  console.log('');
35	  console.log('도구     파일         존재   상태');
36	  for (const it of ov.items) {
37	    let state = '✗ 없음';
38	    if (it.exists) {
39	      if (!ov.canonicalExists) {
40	        state = '· canonical 없음';
41	      } else {
42	        const d = core.diffFor(it.tool);
43	        state = d.hasChanges ? '⚠ drift(다름)' : '✓ 동일';
44	      }
45	    }
46	    console.log(it.tool.padEnd(8) + it.name.padEnd(12) + (it.exists ? '✓' : '✗').padEnd(6) + state);
47	  }
48	  // T2: 등록 프로젝트의 지시문은 존재 여부만 표시 (pull/push는 글로벌 전용 — 범위 밖)
49	  const pj = ov.projectItems || [];
50	  if (pj.length) {
51	    console.log('\n프로젝트 지시문 (존재만 표시):');
52	    const byRoot = new Map();
53	    for (const it of pj) {
54	      if (!byRoot.has(it.projectRoot)) byRoot.set(it.projectRoot, []);
55	      byRoot.get(it.projectRoot).push(it);
56	    }
57	    for (const [root, items] of byRoot) {
58	      console.log('  ' + root);
59	      for (const it of items) {
60	        console.log('    ' + it.tool.padEnd(8) + it.name.padEnd(20) + (it.exists ? '✓' : '✗'));
61	      }
62	    }
63	  }
64	}
65	
66	function cmdPull(args) {
67	  const from = args.from;
68	  if (!from) {
69	    console.error('사용법: aad pull --from <claude|codex|gemini> [--pi-ack <mask|exclude|proceed>]');
70	    process.exit(1);
71	  }
72	  try {
73	    const r = core.pull({ from, piAck: args['pi-ack'] });
74	    if (!r.imported) {
75	      console.log('PI 게이트: 사용자가 제외를 선택 → 가져오지 않았습니다.');
76	      return;
77	    }
