'use strict';
// 데이터 소스 모드. 대시보드 상단 토글로 전환한다.
//  - 'dummy' : 프로젝트 안 fixtures/ 를 읽는다(안전 — 실제 파일 안 건드림). 기본값.
//  - 'real'  : 실제 ~/.claude · ~/.codex · ~/.gemini · ~/.agents 를 읽는다.
//
// ★ 보안 가드(중요): 실제 모드는 환경변수 AAD_ALLOW_REAL=1 이 있어야만 켜진다.
//   이 옵트인이 없으면 setMode('real')은 무시되고 dummy로 남는다.
//   → 서브에이전트/헤드리스/실수로 실제 데이터를 읽거나 쓰는 것을 코드 차원에서 차단한다.
//   사용자가 실제로 쓸 때만: `AAD_ALLOW_REAL=1 node bin/aad.js serve` 처럼 명시적으로 켠다.

// 실제 모드 허용 여부(옵트인). 프로세스 시작 시 환경변수로 결정.
function realAllowed() {
  return process.env.AAD_ALLOW_REAL === '1';
}

// 초기값: AAD_MODE=real 이라도 옵트인이 없으면 dummy로 강등.
let current = process.env.AAD_MODE === 'real' && realAllowed() ? 'real' : 'dummy';

function getMode() {
  return current;
}

// 모드 전환. real 요청은 옵트인(AAD_ALLOW_REAL=1)이 있을 때만 허용.
// 반환값은 "실제로 적용된" 모드(차단되면 dummy 유지).
function setMode(m) {
  if (m === 'real') {
    if (!realAllowed()) return current; // 차단: dummy 유지
    current = 'real';
  } else if (m === 'dummy') {
    current = 'dummy';
  }
  return current;
}

module.exports = { getMode, setMode, realAllowed };
