'use strict';
// 격리 스모크: dummy 모드(기본) + canonical/backups를 스크래치로 오버라이드해
// 실제 홈·실제 canonical·실제 backups를 절대 건드리지 않는다. 빈 포트 43198.
const path = require('path');
const os = require('os');
const fs = require('fs');
const http = require('http');

const SCRATCH = process.env.SCRATCH;
process.env.AAD_CANONICAL = path.join(SCRATCH, 'canonical');
process.env.AAD_BACKUPS = path.join(SCRATCH, 'backups');
// AAD_ALLOW_REAL 미설정 → real 강등, dummy 강제. AAD_MODE 미설정.
fs.mkdirSync(process.env.AAD_CANONICAL, { recursive: true });
fs.mkdirSync(process.env.AAD_BACKUPS, { recursive: true });

const PROJ = '/Users/won-yechan/miru_github/agent-dashboard';
const serve = require(path.join(PROJ, 'server', 'serve.js'));
const PORT = 43198;

function req(method, p, body) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const r = http.request(
      { host: '127.0.0.1', port: PORT, path: p, method, headers: data ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data) } : {} },
      (res) => {
        let buf = '';
        res.on('data', (c) => (buf += c));
        res.on('end', () => resolve({ status: res.statusCode, body: buf }));
      }
    );
    r.on('error', reject);
    if (data) r.write(data);
    r.end();
  });
}

(async () => {
  const server = serve.start({ port: PORT });
  await new Promise((r) => setTimeout(r, 300));
  const out = {};
  try {
    // 1) matrix skill — tools 키가 claude/codex 2개뿐인지
    const mx = await req('GET', '/matrix?kind=skill');
    let toolKeys = null;
    try {
      const j = JSON.parse(mx.body);
      const allKeys = new Set();
      for (const row of j.rows || []) for (const k of Object.keys(row.tools || {})) allKeys.add(k);
      toolKeys = [...allKeys].sort();
    } catch (e) { toolKeys = 'PARSE_FAIL:' + e.message; }
    out.matrix_skill = { status: mx.status, toolKeys };

    // 2) instr matrix — models 키 개수/이름
    const im = await req('GET', '/instr/matrix');
    let models = null;
    try { models = Object.keys(JSON.parse(im.body).models || {}).sort(); } catch (e) { models = 'PARSE_FAIL'; }
    out.instr_matrix = { status: im.status, models };

    // 3) instr sync base=gemini → 명확한 오류(4xx/5xx), 크래시 없음
    const bad = await req('POST', '/instr/sync', { base: 'gemini', apply: false });
    let errMsg = null;
    try { errMsg = JSON.parse(bad.body).error; } catch { errMsg = bad.body.slice(0, 120); }
    out.instr_sync_gemini = { status: bad.status, hasError: bad.status >= 400, error: errMsg };

    // 4) overview / store 200
    const ov = await req('GET', '/overview');
    out.overview = { status: ov.status };
    const st = await req('GET', '/store');
    out.store = { status: st.status };

    // 5) 서버가 여전히 살아있는지(크래시 없음) 재확인
    const alive = await req('GET', '/overview');
    out.alive_after_bad = { status: alive.status };
  } finally {
    server.close(() => {});
  }
  console.log(JSON.stringify(out, null, 2));
  setTimeout(() => process.exit(0), 100);
})().catch((e) => { console.error('SMOKE_FATAL', e); process.exit(1); });

